import { useState } from "react";
import { Eye, EyeOff, Lock, Mail, GraduationCap, BookOpen, Shield } from "lucide-react";

const LOGO = "data:image/jpeg;base64,";

const roles = [
  {
    key: "admin",
    label: "Administrateur",
    icon: Shield,
    color: "from-blue-600 to-blue-800",
    lightColor: "bg-blue-50",
    borderColor: "border-blue-500",
    textColor: "text-blue-600",
    placeholder_login: "admin@digischool.sn",
    login_label: "Email administrateur",
    description: "Acces complet a la plateforme",
  },
  {
    key: "enseignant",
    label: "Enseignant",
    icon: BookOpen,
    color: "from-indigo-600 to-indigo-800",
    lightColor: "bg-indigo-50",
    borderColor: "border-indigo-500",
    textColor: "text-indigo-600",
    placeholder_login: "prof@digischool.sn",
    login_label: "Email enseignant",
    description: "Gestion des cours et des notes",
  },
  {
    key: "etudiant",
    label: "Etudiant",
    icon: GraduationCap,
    color: "from-sky-600 to-sky-800",
    lightColor: "bg-sky-50",
    borderColor: "border-sky-500",
    textColor: "text-sky-600",
    placeholder_login: "ETU-0001",
    login_label: "Matricule etudiant",
    description: "Suivi de votre scolarite",
  },
];

export default function Login() {
  const [roleActif, setRoleActif] = useState("admin");
  const [login, setLogin]         = useState("");
  const [password, setPassword]   = useState("");
  const [showPwd, setShowPwd]     = useState(false);
  const [loading, setLoading]     = useState(false);
  const [error, setError]         = useState("");

  // Mot de passe oublie (modale simulee)
  const [showForgot, setShowForgot]       = useState(false);
  const [forgotEmail, setForgotEmail]     = useState("");
  const [forgotSent, setForgotSent]       = useState(false);
  const [forgotError, setForgotError]     = useState("");

  const handleForgotSubmit = () => {
    setForgotError("");
    const value = forgotEmail.trim();
    if (!value) {
      setForgotError("Veuillez saisir votre email ou matricule.");
      return;
    }
    // Simulation : on affiche un message de confirmation
    setForgotSent(true);
  };

  const closeForgot = () => {
    setShowForgot(false);
    setForgotSent(false);
    setForgotEmail("");
    setForgotError("");
  };

  const role = roles.find((r) => r.key === roleActif);
  const Icon = role.icon;

  const handleSubmit = async () => {
    if (!login || !password) {
      setError("Veuillez remplir tous les champs.");
      return;
    }
    setError("");
    setLoading(true);

    try {
      const BASE = `${import.meta.env.VITE_API_URL}/api`;
      let res, data;

      if (roleActif === "etudiant") {
        res = await fetch(`${BASE}/auth/login-etudiant`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ matricule: login, password }),
        });
      } else {
        res = await fetch(`${BASE}/auth/login`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ email: login, password }),
        });
      }

      data = await res.json();

      if (!res.ok) {
        throw new Error(data.message || "Identifiants incorrects.");
      }

      localStorage.setItem("token", data.token);
      localStorage.setItem("role", data.user.role);
      localStorage.setItem("user", JSON.stringify(data.user));

      if (data.user.role === "admin") {
        window.location.href = "/";
      } else if (data.user.role === "enseignant") {
        window.location.href = "/enseignant/dashboard";
      } else {
        window.location.href = "/etudiant/dashboard";
      }

    } catch (err) {
      // Si backend pas encore pret, connexion demo
      if (err.message === "Failed to fetch") {
        setError("Backend non disponible. Mode demo active.");
        setTimeout(() => {
          if (roleActif === "admin") {
            localStorage.setItem("token", "demo-token");
            localStorage.setItem("role", "admin");
            localStorage.setItem("user", JSON.stringify({ nom: "Lamine Ndong", role: "admin", email: "admin@dgs.sn" }));
            window.location.href = "/";
          } else if (roleActif === "enseignant") {
            localStorage.setItem("token", "demo-token");
            localStorage.setItem("role", "enseignant");
            localStorage.setItem("user", JSON.stringify({ nom: "M. Ibrahima Diallo", role: "enseignant", email: "i.diallo@dgs.sn", matiere: "Mathematiques" }));
            window.location.href = "/enseignant/dashboard";
          } else {
            localStorage.setItem("token", "demo-token");
            localStorage.setItem("role", "etudiant");
            localStorage.setItem("user", JSON.stringify({ nom: "Khadija Diop", role: "etudiant", matricule: "ETU-0042" }));
            window.location.href = "/etudiant/dashboard";
          }
        }, 1000);
      } else {
        setError(err.message);
      }
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-900 via-blue-800 to-blue-600 flex items-center justify-center p-4">
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-32 -left-32 w-96 h-96 bg-white/5 rounded-full blur-3xl" />
        <div className="absolute -bottom-32 -right-32 w-96 h-96 bg-blue-400/10 rounded-full blur-3xl" />
      </div>

      <div className="w-full max-w-md relative z-10">

        {/* LOGO */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center mb-3">
            <div className="bg-white rounded-full p-2 shadow-lg border-2 border-white/30">
              <img src={LOGO} alt="DigiSchool" className="h-9 w-9 object-contain rounded-full" />
            </div>
          </div>
          <h1 className="font-serif text-2xl font-bold text-white">DigiSchool</h1>
          <p className="text-blue-200/70 text-xs mt-1 tracking-widest uppercase">L'ecole du numerique</p>
        </div>

        {/* CARD */}
        <div className="bg-white rounded-3xl shadow-2xl overflow-hidden">

          {/* Onglets roles */}
          <div className="grid grid-cols-3 border-b border-gray-100">
            {roles.map((r) => {
              const RIcon = r.icon;
              const isActive = roleActif === r.key;
              return (
                <button key={r.key}
                  onClick={() => { setRoleActif(r.key); setError(""); setLogin(""); }}
                  className={`flex flex-col items-center gap-1.5 py-4 px-2 text-center transition-all duration-200 border-b-2
                    ${isActive ? r.borderColor + " " + r.lightColor + " " + r.textColor : "border-transparent text-gray-400 hover:bg-gray-50"}`}>
                  <RIcon size={20} />
                  <span className="text-[11.5px] font-semibold">{r.label}</span>
                </button>
              );
            })}
          </div>

          <div className="p-8">

            {/* Role header */}
            <div className={`flex items-center gap-3 p-3.5 rounded-2xl ${role.lightColor} mb-6`}>
              <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${role.color} flex items-center justify-center flex-shrink-0 shadow-md`}>
                <Icon size={20} className="text-white" />
              </div>
              <div>
                <p className={`text-[14px] font-bold ${role.textColor}`}>Connexion {role.label}</p>
                <p className="text-[11.5px] text-gray-500">{role.description}</p>
              </div>
            </div>

            {/* Erreur */}
            {error && (
              <div className="flex items-center gap-2 bg-red-50 border border-red-200 text-red-600 text-[13px] rounded-xl px-4 py-3 mb-4">
                ⚠️ {error}
              </div>
            )}

            {/* Champ login */}
            <div className="mb-4">
              <label className="block text-[12.5px] font-semibold text-gray-600 mb-1.5">{role.login_label}</label>
              <div className="relative">
                <div className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400"><Mail size={16} /></div>
                <input type={roleActif === "etudiant" ? "text" : "email"} value={login}
                  onChange={(e) => setLogin(e.target.value)}
                  placeholder={role.placeholder_login}
                  className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl text-[13.5px] text-gray-800 placeholder-gray-400 outline-none focus:border-blue-400 focus:ring-2 focus:ring-blue-100 transition-all font-sans" />
              </div>
            </div>

            {/* Mot de passe */}
            <div className="mb-6">
              <div className="flex items-center justify-between mb-1.5">
                <label className="text-[12.5px] font-semibold text-gray-600">Mot de passe</label>
                <button type="button" onClick={() => setShowForgot(true)} className="text-[12px] text-blue-500 hover:text-blue-700 font-medium">Mot de passe oublie ?</button>
              </div>
              <div className="relative">
                <div className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400"><Lock size={16} /></div>
                <input type={showPwd ? "text" : "password"} value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
                  placeholder="••••••••"
                  className="w-full pl-10 pr-11 py-3 border border-gray-200 rounded-xl text-[13.5px] text-gray-800 placeholder-gray-400 outline-none focus:border-blue-400 focus:ring-2 focus:ring-blue-100 transition-all font-sans" />
                <button onClick={() => setShowPwd(!showPwd)}
                  className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600">
                  {showPwd ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            {/* Bouton connexion */}
            <button onClick={handleSubmit} disabled={loading}
              className={`w-full py-3.5 rounded-xl text-white text-[14px] font-bold transition-all duration-200 shadow-lg
                ${loading ? "bg-gray-300 cursor-not-allowed" : "bg-gradient-to-r " + role.color + " hover:shadow-xl hover:scale-[1.01] active:scale-[0.99]"}`}>
              {loading ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-4 w-4" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z"/>
                  </svg>
                  Connexion en cours...
                </span>
              ) : "Se connecter en tant que " + role.label}
            </button>

            {/* Identifiants demo */}
            <div className="mt-5 p-4 bg-gray-50 rounded-2xl border border-gray-100">
              <p className="text-[11px] font-bold text-gray-500 uppercase tracking-wide mb-2">Identifiants de demonstration</p>
              {roleActif === "admin" && (
                <div className="text-[12px] text-gray-600 space-y-1">
                  <p>Email : <span className="font-semibold text-blue-600">admin@digischool.sn</span></p>
                  <p>Mot de passe : <span className="font-semibold text-blue-600">admin123</span></p>
                </div>
              )}
              {roleActif === "enseignant" && (
                <div className="text-[12px] text-gray-600 space-y-1">
                  <p>Email : <span className="font-semibold text-indigo-600">i.diallo@dgs.sn</span></p>
                  <p>Mot de passe : <span className="font-semibold text-indigo-600">prof123</span></p>
                </div>
              )}
              {roleActif === "etudiant" && (
                <div className="text-[12px] text-gray-600 space-y-1">
                  <p>Matricule : <span className="font-semibold text-sky-600">ETU-0042</span></p>
                  <p>Mot de passe : <span className="font-semibold text-sky-600">etudiant123</span></p>
                </div>
              )}
            </div>
          </div>
        </div>

        <p className="text-center text-blue-200/50 text-[11px] mt-5">DigiSchool — L'ecole du Numerique © 2026</p>
      </div>

      {/* MODALE MOT DE PASSE OUBLIE (simulee) */}
      {showForgot && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4" onClick={closeForgot}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-7" onClick={(e) => e.stopPropagation()}>
            {!forgotSent ? (
              <>
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-11 h-11 rounded-xl bg-blue-50 flex items-center justify-center">
                    <Lock className="text-blue-600" size={20} />
                  </div>
                  <div>
                    <h3 className="font-serif text-lg font-bold text-blue-900">Mot de passe oublie</h3>
                    <p className="text-[12px] text-gray-500">Reinitialisez votre acces</p>
                  </div>
                </div>
                <p className="text-[13px] text-gray-600 mb-4">
                  Saisissez votre email (ou matricule pour les etudiants). Un lien de reinitialisation vous sera envoye.
                </p>
                {forgotError && (
                  <div className="bg-red-50 border border-red-200 text-red-600 text-[13px] rounded-lg px-3 py-2 mb-3">
                    {forgotError}
                  </div>
                )}
                <div className="flex items-center gap-2 border border-gray-200 rounded-xl px-4 py-3 mb-5">
                  <Mail className="text-gray-400" size={18} />
                  <input
                    value={forgotEmail}
                    onChange={(e) => setForgotEmail(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && handleForgotSubmit()}
                    placeholder="email@digischool.sn ou ETU-0001"
                    className="flex-1 outline-none text-[14px] text-gray-700"
                  />
                </div>
                <div className="flex gap-3">
                  <button onClick={closeForgot} className="flex-1 py-3 rounded-xl border border-gray-200 text-gray-600 font-medium text-[14px] hover:bg-gray-50">
                    Annuler
                  </button>
                  <button onClick={handleForgotSubmit} className="flex-1 py-3 rounded-xl bg-gradient-to-r from-blue-600 to-blue-800 text-white font-semibold text-[14px] shadow-lg">
                    Envoyer le lien
                  </button>
                </div>
              </>
            ) : (
              <div className="text-center py-4">
                <div className="w-14 h-14 rounded-full bg-green-50 flex items-center justify-center mx-auto mb-4">
                  <span className="text-green-500 text-3xl">✓</span>
                </div>
                <h3 className="font-serif text-lg font-bold text-blue-900 mb-2">Email envoye !</h3>
                <p className="text-[13.5px] text-gray-600 mb-1">
                  Si un compte est associe a <span className="font-semibold text-blue-700">{forgotEmail}</span>,
                  vous recevrez un lien de reinitialisation.
                </p>
                <p className="text-[12px] text-gray-400 mb-5">Pensez a verifier vos spams.</p>
                <button onClick={closeForgot} className="w-full py-3 rounded-xl bg-gradient-to-r from-blue-600 to-blue-800 text-white font-semibold text-[14px] shadow-lg">
                  Retour a la connexion
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}